  ('shatavari', 'Review', 'PMC4027291 - Phytochemie Review', 'https://pmc.ncbi.nlm.nih.gov/articles/PMC4027291/', '2025-12-24', 'Umfassender Review zu Phytochemie und Pharmakologie von A. racemosus', 'Hoch'),
